//! Golden trajectory parity against the Python reference (PLAN.md M2 exit
//! criterion: per-iteration parity on a tiny fixed problem over 12 iters).
//!
//! Inputs are generated by a deterministic sin-formula both sides implement
//! identically (no RNG stream replication). The expected values below were
//! produced by `sheaf_admm.admm.run_admm_history` (JAX fp32) with:
//! FixedGeometry over edges [[0,1],[0,2],[1,3],[2,3],[0,3]], N=4, B=2, d_v=4,
//! d_e=2; DiagonalProxXSolver with the L1+box objective (lower=0); prox-mode
//! UnrolledCG gamma=5, T=5; rho=0.25, alpha=1.0, K=12.

// Golden literals are verbatim fp32 dumps from the Python run.
#![allow(clippy::excessive_precision)]

mod common;

use common::*;

use ndarray::{s, Array3, Array4};
use sheaf_core::admm::{run_admm_history, AdmmParams, XSolverKind};
use sheaf_core::geometry::FixedGeometry;
use sheaf_core::solvers::{EncoderOutput, Objective, UnrolledCgParams, ZMode};

const N: usize = 4;
const B: usize = 2;
const D_V: usize = 4;
const D_E: usize = 2;
const K: usize = 12;

/// `sin(7*i0 + 3*i1 + 5*i2 + 1*i3 + off) * scale`, all in f32 — mirrors the
/// generator in the Python golden script exactly.
fn arr3(shape: (usize, usize, usize), off: f32, scale: f32) -> Array3<f32> {
    Array3::from_shape_fn(shape, |(i, j, k)| {
        ((i as f32) * 7.0 + (j as f32) * 3.0 + (k as f32) * 5.0 + off).sin() * scale
    })
}

fn arr4(shape: (usize, usize, usize, usize), off: f32, scale: f32) -> Array4<f32> {
    Array4::from_shape_fn(shape, |(i, j, k, l)| {
        ((i as f32) * 7.0 + (j as f32) * 3.0 + (k as f32) * 5.0 + (l as f32) + off).sin() * scale
    })
}

