#[test]
fn golden_trajectory_matches_python_reference() {
    let graph = tiny_graph(); // edges [[0,1],[0,2],[1,3],[2,3],[0,3]]
    let e = graph.num_edges();
    let maps = arr4((e, 2, D_E, D_V), 0.1, 0.6);
    let geo = FixedGeometry::new(graph, maps);

    let z_init = arr3((N, B, D_V), 0.7, 0.5);
    let q_diag = arr3((N, B, D_V), 1.3, 0.5).mapv(|v| v.abs() + 0.1);
    let q = arr3((N, B, D_V), 2.1, 0.5);
    let l1 = arr3((N, B, D_V), 3.3, 0.05).mapv(f32::abs);
    let upper = arr3((N, B, D_V), 4.7, 0.5).mapv(|v| v.abs() + 0.5);

    let enc = EncoderOutput {
        h: z_init.clone(),
        objective: Objective::L1Box { q_diag, q, l1, upper },
        lora: None,
    };
    let z_params = UnrolledCgParams {
        mode: ZMode::Prox,
        gamma: 5.0,
        num_iters: 5,
        tikhonov_eps: 1e-5,
    };
    let params = AdmmParams { rho: 0.25, alpha: 1.0, gamma: 5.0, k: K };

    let (state, hist) =
        run_admm_history(&enc, &geo, XSolverKind::DiagonalProx, &z_params, &params, &z_init);

    // Widening tolerance schedule (PLAN.md §5.2): fp32 accumulation-order
    // drift compounds over the unroll; 12 iters stays well within 1e-5-ish.
    for k in 0..K {
        #[allow(clippy::needless_range_loop)]
        for b in 0..B {
            let got = hist.consistency_rms[[k, b]];
            let want = GOLDEN_CRMS[k][b];
            assert!(
                (got - want).abs() <= 2e-6,
                "consistency_rms[{k},{b}]: {got} vs golden {want}"
            );
        }
        let p_mean = hist.primal_res.slice(s![k, .., ..]).mean().unwrap();
        assert!(
            (p_mean - GOLDEN_PRIMAL_MEAN[k]).abs() <= 5e-6,
            "primal_res mean[{k}]: {p_mean} vs golden {}",
            GOLDEN_PRIMAL_MEAN[k]
        );
        let d_mean = hist.dual_res.slice(s![k, .., ..]).mean().unwrap();
        assert!(
            (d_mean - GOLDEN_DUAL_MEAN[k]).abs() <= 5e-6,
            "dual_res mean[{k}]: {d_mean} vs golden {}",
            GOLDEN_DUAL_MEAN[k]
        );
    }

    for (i, ((&gx, &gz), &gy)) in state
        .x
        .iter()
        .zip(state.z.iter())
        .zip(state.y.iter())
        .enumerate()
    {
        assert!(
            (gx - GOLDEN_FINAL_X[i]).abs() <= 2e-5,
            "final x[{i}]: {gx} vs golden {}",
            GOLDEN_FINAL_X[i]
        );
        assert!(
            (gz - GOLDEN_FINAL_Z[i]).abs() <= 2e-5,
            "final z[{i}]: {gz} vs golden {}",
            GOLDEN_FINAL_Z[i]
        );
        assert!(
            (gy - GOLDEN_FINAL_Y[i]).abs() <= 5e-5,
            "final y[{i}]: {gy} vs golden {}",
            GOLDEN_FINAL_Y[i]
        );
    }
}
